// ----- Scenario 3: Log Divergence -----

fn scenario_log_divergence(engine: SimulationEngine) -> SimulationEngine {
    print("=== Scenario 3: Log Divergence ===");

    // Client request to leader
    let request_event = SimEvent {
        time_ms: 100,
        event_type: SimEventType.ClientRequest,
        node_id: 0,
        from_node: 0,
        to_node: 0,
        key: "key1",
        value: "value1",
        delay_ms: 0,
        loss_rate: 0.0,
    };

    engine = add_event(engine, request_event);

    // Network partition before replication
    let partition_event = SimEvent {
        time_ms: 150,
        event_type: SimEventType.NetworkPartition,
        node_id: 0,
        from_node: 0,
        to_node: 1,
        key: "",
        value: "",
        delay_ms: 0,
        loss_rate: 0.0,
    };

    engine = add_event(engine, partition_event);

    // Leader changes in partition
    let election_event = SimEvent {
        time_ms: 300,
