// ----- Scenario 4: High Load -----

fn scenario_high_load(engine: SimulationEngine) -> SimulationEngine {
    print("=== Scenario 4: High Load (1000 writes/sec) ===");

    // Burst of 100 writes in 100ms
    let i = 0;
    while (i < 100) {
        let write_event = SimEvent {
            time_ms: 100 + (i as u64),
            event_type: SimEventType.ClientRequest,
            node_id: 0,
