    engine
}

// ----- Scenario 5: Cascading Failure -----

fn scenario_cascading_failure(engine: SimulationEngine) -> SimulationEngine {
    print("=== Scenario 5: Cascading Failure ===");

    // Node 0 crashes
    let crash0 = SimEvent {
        time_ms: 100,
        event_type: SimEventType.NodeCrash,
        node_id: 0,
        from_node: 0,
        to_node: 0,
        key: "",
        value: "",
        delay_ms: 0,
        loss_rate: 0.0,
    };

    engine = add_event(engine, crash0);

    // Node 1 crashes (before recovery)
    let crash1 = SimEvent {
        time_ms: 200,
        event_type: SimEventType.NodeCrash,
        node_id: 1,
        from_node: 0,
        to_node: 0,
        key: "",
        value: "",
        delay_ms: 0,
        loss_rate: 0.0,
    };

    engine = add_event(engine, crash1);

    // Node 0 recovers
    let restart0 = SimEvent {
        time_ms: 400,
        event_type: SimEventType.NodeRestart,
        node_id: 0,
        from_node: 0,
        to_node: 0,
        key: "",
        value: "",
        delay_ms: 0,
        loss_rate: 0.0,
    };

    engine = add_event(engine, restart0);

    // Node 1 recovers
    let restart1 = SimEvent {
        time_ms: 500,
        event_type: SimEventType.NodeRestart,
        node_id: 1,
        from_node: 0,
        to_node: 0,
        key: "",
        value: "",
        delay_ms: 0,
        loss_rate: 0.0,
    };

    engine = add_event(engine, restart1);

    engine = sort_events(engine);

    print("Timeline:");
    print("  100ms: Node 0 crashes");
    print("  200ms: Node 1 crashes");
    print("  400ms: Node 0 restarts");
    print("  500ms: Node 1 restarts");
    print("Expected: Cluster survives (quorum recovery)");

    engine
}

// ----- Execution -----

fn process_event(engine: SimulationEngine, event: SimEvent) -> SimulationEngine {
    let event_type_str = match event.event_type {
        SimEventType.NodeCrash => "NodeCrash",
        SimEventType.NodeRestart => "NodeRestart",
        SimEventType.NetworkDelay => "NetworkDelay",
        SimEventType.PacketLoss => "PacketLoss",
        SimEventType.NetworkPartition => "NetworkPartition",
        SimEventType.ClientRequest => "ClientRequest",
        SimEventType.ClientResponse => "ClientResponse",
        SimEventType.ElectionTimeout => "ElectionTimeout",
        SimEventType.HeartbeatTimeout => "HeartbeatTimeout",
    };

    print("T+" + event.time_ms + "ms: " + event_type_str + " (Node " + event.node_id + ")");

    engine.metrics.events_processed = engine.metrics.events_processed + 1;
    engine
}

fn run_scenario(engine: SimulationEngine, scenario_name: string) -> SimulationEngine {
    print("");
    print("Running: " + scenario_name);
    print("Seed: " + engine.random_seed);

    // Run appropriate scenario
    if (scenario_name == "leader_election") {
        engine = scenario_leader_election(engine);
    } else if (scenario_name == "network_partition") {
        engine = scenario_network_partition(engine);
    } else if (scenario_name == "log_divergence") {
        engine = scenario_log_divergence(engine);
    } else if (scenario_name == "high_load") {
        engine = scenario_high_load(engine);
    } else if (scenario_name == "cascading_failure") {
        engine = scenario_cascading_failure(engine);
    };

    // Process all events in order
    let i = 0;
    while (i < engine.events.len()) {
        engine = process_event(engine, engine.events[i]);
        i = i + 1;
    };

    print("");

    engine
}

// ----- Report Generation -----

fn generate_report(engine: SimulationEngine, scenario: string) -> SimulationResult {
    let duration = engine.current_time;
    let passed = engine.metrics.events_processed > 0;

    let description = match scenario {
        "leader_election" => "Leader crashes, new election within 150-300ms",
        "network_partition" => "Network split into 2, majority continues",
        "log_divergence" => "Conflicting logs resolved on recovery",
        "high_load" => "1000 writes/sec processed successfully",
        "cascading_failure" => "2 simultaneous crashes, recovery on restart",
        _ => "Unknown scenario",
    };

    SimulationResult {
        scenario: scenario,
        duration_ms: duration,
        passed: passed,
        metrics: engine.metrics,
        description: description,
    }
}

fn print_report(result: SimulationResult) {
    let status = if (result.passed) "✓ PASS" else "✗ FAIL";

    print("=== Simulation Report ===");
    print("Scenario: " + result.scenario);
    print("Status: " + status);
    print("Duration: " + result.duration_ms + "ms");
    print("Events: " + result.metrics.events_processed);
    print("Description: " + result.description);
    print("");
}

// ----- High-Level Runner -----

fn run_all_scenarios() {
    print("===============================================");
    print("Deterministic Simulation Testing - Week 3");
    print("===============================================");
    print("");

    let seed = 12345;
    let results = [];

    // Scenario 1: Leader Election
    let engine1 = new_simulation_engine(3, seed);
    let engine1_result = run_scenario(engine1, "leader_election");
    let result1 = generate_report(engine1_result, "leader_election");
    results.push(result1);
    print_report(result1);

    // Scenario 2: Network Partition
    let engine2 = new_simulation_engine(3, seed);
    let engine2_result = run_scenario(engine2, "network_partition");
    let result2 = generate_report(engine2_result, "network_partition");
    results.push(result2);
    print_report(result2);

    // Scenario 3: Log Divergence
    let engine3 = new_simulation_engine(3, seed);
    let engine3_result = run_scenario(engine3, "log_divergence");
    let result3 = generate_report(engine3_result, "log_divergence");
    results.push(result3);
    print_report(result3);

    // Scenario 4: High Load
    let engine4 = new_simulation_engine(3, seed);
    let engine4_result = run_scenario(engine4, "high_load");
    let result4 = generate_report(engine4_result, "high_load");
    results.push(result4);
    print_report(result4);

    // Scenario 5: Cascading Failure
    let engine5 = new_simulation_engine(3, seed);
    let engine5_result = run_scenario(engine5, "cascading_failure");
    let result5 = generate_report(engine5_result, "cascading_failure");
    results.push(result5);
    print_report(result5);

    // Summary
    print("===============================================");
    print("Summary: " + results.len() + " scenarios executed");
    let passed_count = 0;
    let i = 0;
    while (i < results.len()) {
        if (results[i].passed) {
            passed_count = passed_count + 1;
        };
        i = i + 1;
    };

    print("Passed: " + passed_count + " / " + results.len());
    print("===============================================");
}

// Main entry point
run_all_scenarios();

