// Test framework
struct TestResult {
    name: string,
    passed: bool,
    message: string,
}

fn assert_equal_u64(actual: u64, expected: u64, test_name: string) -> TestResult {
    TestResult {
        name: test_name,
        passed: actual == expected,
        message: if (actual == expected) "PASS" else "FAIL",
    }
}

fn assert_true(condition: bool, test_name: string) -> TestResult {
    TestResult {
        name: test_name,
        passed: condition,
        message: if (condition) "PASS" else "FAIL",
    }
}

fn print_test_result(result: TestResult) {
    let status = if (result.passed) "✓" else "✗";
    print(status + " " + result.name + ": " + result.message);
